#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>

// Simple hash map with separate chaining for k-mer -> node

typedef struct Node {
    char *kmer;
    char left;
    char right;
    int visited;
    struct Node *next; // for chaining in hash bucket
} Node;

typedef struct {
    Node **buckets;
    size_t nbuckets;
} Hash;

static unsigned long hash_str(const char *s) {
    unsigned long h = 1469598103934665603ULL; // FNV-1a 64-bit
    while (*s) {
        h ^= (unsigned char)(*s++);
        h *= 1099511628211ULL;
    }
    return h;
}

static Hash *hash_create(size_t nb) {
    Hash *h = (Hash*)calloc(1, sizeof(Hash));
    h->nbuckets = nb;
    h->buckets = (Node**)calloc(nb, sizeof(Node*));
    return h;
}

static void hash_insert(Hash *h, Node *n) {
    unsigned long hv = hash_str(n->kmer);
    size_t idx = hv % h->nbuckets;
    n->next = h->buckets[idx];
    h->buckets[idx] = n;
}

static Node* hash_find(Hash *h, const char *key) {
    unsigned long hv = hash_str(key);
    size_t idx = hv % h->nbuckets;
    for (Node *p = h->buckets[idx]; p; p = p->next) {
        if (strcmp(p->kmer, key) == 0) return p;
    }
    return NULL;
}

static void chomp(char *s) {
    size_t n = strlen(s);
    while (n && (s[n-1] == '\n' || s[n-1] == '\r')) s[--n] = '\0';
}

int main(int argc, char **argv) {
    const char *infile = (argc > 1) ? argv[1] : "test";
    FILE *fp = fopen(infile, "r");
    if (!fp) { perror("open input"); return 1; }

    // First pass: count lines and detect k
    size_t nlines = 0;
    size_t K = 0;
    char buf[4096];
    while (fgets(buf, sizeof(buf), fp)) {
        if (buf[0] == '\0' || buf[0] == '\n') continue;
        char *tab = strchr(buf, '\t');
        if (!tab) continue;
        size_t len = (size_t)(tab - buf);
        if (K == 0) K = len;
        nlines++;
    }
    if (K == 0 || nlines == 0) { fclose(fp); fprintf(stderr, "Empty or invalid input\n"); return 1; }
    rewind(fp);

    // Create hash with 2x buckets to reduce collisions
    size_t nbuckets = 1;
    while (nbuckets < nlines * 2) nbuckets <<= 1;
    Hash *H = hash_create(nbuckets);

    // Allocate and load nodes
    Node *nodes = (Node*)calloc(nlines, sizeof(Node));
    size_t idx = 0;
    while (fgets(buf, sizeof(buf), fp)) {
        if (buf[0] == '\0' || buf[0] == '\n') continue;
        chomp(buf);
        char *tab = strchr(buf, '\t');
        if (!tab) continue;
        *tab = '\0';
        char *ext = tab + 1;
        if (strlen(ext) < 2) continue;
        nodes[idx].kmer = strdup(buf);
        nodes[idx].left = ext[0];
        nodes[idx].right = ext[1];
        nodes[idx].visited = 0;
        nodes[idx].next = NULL;
        hash_insert(H, &nodes[idx]);
        idx++;
    }
    fclose(fp);

    // Prepare output
    FILE *out = fopen("serial.out", "w");
    if (!out) { perror("serial.out"); return 1; }

    // Helper buffer for next k-mer computation
    char *nextk = (char*)malloc(K + 1);

    // Function to extend from a start node
    for (size_t i = 0; i < nlines; i++) {
        Node *n = &nodes[i];
        if (n->visited) continue;
        if (n->left != 'F') continue; // start at nodes with no incoming

        // Begin contig with the k-mer
        char *contig = (char*)malloc(K + 1024 + 1); // will grow if needed
        size_t cap = K + 1024;
        size_t clen = 0;
        size_t need = K + 1;
        if (cap < need) { cap = need; contig = (char*)realloc(contig, cap); }
        memcpy(contig, n->kmer, K);
        clen = K;
        n->visited = 1;

        Node *cur = n;
        while (cur->right != 'F') {
            // compute next k-mer: suffix of current + right char
            memmove(nextk, cur->kmer + 1, K - 1);
            nextk[K - 1] = cur->right;
            nextk[K] = '\0';
            Node *nn = hash_find(H, nextk);
            if (!nn || nn->visited) break;
            // append last base
            if (clen + 1 + 1 > cap) { cap *= 2; contig = (char*)realloc(contig, cap); }
            contig[clen++] = cur->right;
            cur = nn;
            cur->visited = 1;
        }
        contig[clen] = '\0';
        fprintf(out, "%s\n", contig);
        free(contig);
    }

    // Handle cycles (no node with left=='F')
    for (size_t i = 0; i < nlines; i++) {
        Node *n = &nodes[i];
        if (n->visited) continue;
        // Start here and walk until we return or hit visited
        char *contig = (char*)malloc(K + nlines + 1);
        size_t cap = K + nlines + 1;
        size_t clen = 0;
        memcpy(contig, n->kmer, K);
        clen = K;
        n->visited = 1;
        Node *cur = n;
        size_t steps = 0;
        while (cur->right != 'F' && steps < nlines) {
            memmove(nextk, cur->kmer + 1, K - 1);
            nextk[K - 1] = cur->right;
            nextk[K] = '\0';
            Node *nn = hash_find(H, nextk);
            if (!nn || nn->visited) break;
            contig[clen++] = cur->right;
            cur = nn;
            cur->visited = 1;
            steps++;
        }
        contig[clen] = '\0';
        fprintf(out, "%s\n", contig);
        free(contig);
    }

    fclose(out);
    free(nextk);
    // free memory (optional in short-lived program)
    for (size_t i = 0; i < nlines; i++) free(nodes[i].kmer);
    free(nodes);
    free(H->buckets);
    free(H);
    return 0;
}
