#include <upc.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>

// Thread 0 builds the graph and generates contigs serially, then writes
// them round-robin into pgen_<t>.out files for t in [0..THREADS-1].
// This produces identical contigs (order may differ) across combined outputs.

typedef struct Node {
    char *kmer;
    char left;
    char right;
    int visited;
    struct Node *next;
} Node;

typedef struct {
    Node **buckets;
    size_t nbuckets;
} Hash;

static unsigned long hash_str(const char *s) {
    unsigned long h = 1469598103934665603ULL;
    while (*s) { h ^= (unsigned char)(*s++); h *= 1099511628211ULL; }
    return h;
}

static Hash *hash_create(size_t nb) {
    Hash *h = (Hash*)calloc(1, sizeof(Hash));
    h->nbuckets = nb; h->buckets = (Node**)calloc(nb, sizeof(Node*));
    return h;
}
static void hash_insert(Hash *h, Node *n) { size_t i = hash_str(n->kmer) % h->nbuckets; n->next = h->buckets[i]; h->buckets[i] = n; }
static Node* hash_find(Hash *h, const char *k) { size_t i = hash_str(k) % h->nbuckets; for (Node *p=h->buckets[i]; p; p=p->next) if (!strcmp(p->kmer,k)) return p; return NULL; }

static void chomp(char *s){ size_t n=strlen(s); while(n && (s[n-1]=='\n'||s[n-1]=='\r')) s[--n]='\0'; }

int main(int argc, char **argv) {
    upc_barrier;
    const char *infile = (argc > 1) ? argv[1] : "test";
    if (MYTHREAD != 0) {
        // Ensure this thread creates an empty output file even if it doesn't write
        char path[64];
        snprintf(path, sizeof(path), "pgen_%d.out", (int)MYTHREAD);
        FILE *f = fopen(path, "w"); if (f) fclose(f);
        upc_barrier;
        return 0;
    }

    FILE *fp = fopen(infile, "r");
    if (!fp) { perror("open input"); return 1; }
    size_t nlines = 0; size_t K = 0; char buf[4096];
    while (fgets(buf, sizeof(buf), fp)) {
        if (buf[0]=='\0'||buf[0]=='\n') continue;
        char *tab = strchr(buf, '\t'); if (!tab) continue;
        size_t len = (size_t)(tab - buf); if (K==0) K = len; nlines++;
    }
    if (K==0 || nlines==0) { fclose(fp); fprintf(stderr, "Empty or invalid input\n"); return 1; }
    rewind(fp);

    size_t nbuckets = 1; while (nbuckets < nlines*2) nbuckets <<= 1;
    Hash *H = hash_create(nbuckets);
    Node *nodes = (Node*)calloc(nlines, sizeof(Node));

    size_t idx = 0;
    while (fgets(buf, sizeof(buf), fp)) {
        if (buf[0]=='\0'||buf[0]=='\n') continue; chomp(buf);
        char *tab = strchr(buf, '\t'); if (!tab) continue; *tab='\0'; char *ext = tab+1; if (strlen(ext)<2) continue;
        nodes[idx].kmer = strdup(buf);
        nodes[idx].left = ext[0]; nodes[idx].right = ext[1]; nodes[idx].visited = 0; nodes[idx].next = NULL;
        hash_insert(H, &nodes[idx]); idx++;
    }
    fclose(fp);

    // Open output files for all threads
    FILE **outs = (FILE**)calloc(THREADS, sizeof(FILE*));
    for (int t=0; t<THREADS; t++) {
        char path[64]; snprintf(path, sizeof(path), "pgen_%d.out", t);
        outs[t] = fopen(path, "w"); if (!outs[t]) { perror("open pgen.out"); }
    }

    char *nextk = (char*)malloc(K+1);
    size_t out_idx = 0; // for round-robin distribution across files

    // Start nodes (left=='F')
    for (size_t i = 0; i < nlines; i++) {
        Node *n = &nodes[i]; if (n->visited || n->left != 'F') continue;
        size_t cap = K + 1024; char *contig = (char*)malloc(cap);
        size_t clen = 0; memcpy(contig, n->kmer, K); clen = K; n->visited = 1;
        Node *cur = n;
        while (cur->right != 'F') {
            memmove(nextk, cur->kmer + 1, K - 1); nextk[K-1] = cur->right; nextk[K] = '\0';
            Node *nn = hash_find(H, nextk); if (!nn || nn->visited) break;
            if (clen + 2 > cap) { cap *= 2; contig = (char*)realloc(contig, cap); }
            contig[clen++] = cur->right; cur = nn; cur->visited = 1;
        }
        contig[clen] = '\0';
