        while (cur->right != 'F' && steps < nlines) {
            memmove(nextk, cur->kmer + 1, K - 1); nextk[K-1] = cur->right; nextk[K] = '\0';
            Node *nn = hash_find(H, nextk); if (!nn || nn->visited) break;
            contig[clen++] = cur->right; cur = nn; cur->visited = 1; steps++;
        }
        contig[clen] = '\0';
        int t = (THREADS > 0) ? (int)(out_idx % THREADS) : 0; out_idx++;
        if (outs[t]) fprintf(outs[t], "%s\n", contig);
        free(contig);
    }

    for (int t=0; t<THREADS; t++) if (outs[t]) fclose(outs[t]);
    free(outs);
    free(nextk);
    for (size_t i=0;i<nlines;i++) free(nodes[i].kmer);
    free(nodes); free(H->buckets); free(H);

    upc_barrier;
    return 0;
}
